// Carbon Footprint Calculator
// Calculates CO2 emissions from energy, transportation, and materials

// Parse the input query (expecting JSON string or object)
let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return 'Error: Invalid input format. Expected JSON with energy_kwh, transportation_km, fuel_type, and materials_kg';
}

// Emission factors (kg CO2e per unit)
const EMISSION_FACTORS = {
  // Energy: kg CO2e per kWh
  energy: 0.5, // Average grid electricity

  // Transportation: kg CO2e per km
  fuel_types: {
    diesel: 0.27,
    gasoline: 0.24,
    electric: 0.05,
    hybrid: 0.12,
    air_freight: 1.13,
    sea_freight: 0.01
  },

  // Materials: kg CO2e per kg (production emissions)
  materials: {
    steel: 1.85,
    aluminum: 8.24,
    plastic: 3.79,
    paper: 1.32,
    glass: 0.85,
    default: 2.0
  }
};

// Calculate energy emissions
const energyEmissions = (input.energy_kwh || 0) * EMISSION_FACTORS.energy;

// Calculate transportation emissions
const fuelType = (input.fuel_type || 'diesel').toLowerCase();
const transportFactor = EMISSION_FACTORS.fuel_types[fuelType] || EMISSION_FACTORS.fuel_types.diesel;
const transportEmissions = (input.transportation_km || 0) * transportFactor;

// Calculate material emissions
const materialType = (input.material_type || 'default').toLowerCase();
const materialFactor = EMISSION_FACTORS.materials[materialType] || EMISSION_FACTORS.materials.default;
const materialEmissions = (input.materials_kg || 0) * materialFactor;

// Total carbon footprint
const totalEmissions = energyEmissions + transportEmissions + materialEmissions;

// Return detailed breakdown
const result = {
  total_co2e_kg: Math.round(totalEmissions * 100) / 100,
  breakdown: {
    energy_emissions: Math.round(energyEmissions * 100) / 100,
    transport_emissions: Math.round(transportEmissions * 100) / 100,
    material_emissions: Math.round(materialEmissions * 100) / 100
  },
  inputs: {
    energy_kwh: input.energy_kwh || 0,
    transportation_km: input.transportation_km || 0,
    fuel_type: fuelType,
    materials_kg: input.materials_kg || 0,
    material_type: materialType
  },
  emission_factors_used: {
    energy: EMISSION_FACTORS.energy,
    transport: transportFactor,
    material: materialFactor
  }
};

return JSON.stringify(result, null, 2);
